sp_widget.client_script:
api.controller = function($timeout) {
    var c = this;

    if (c.data.qr_token) {
        $timeout(function() {
            var qrElement = document.getElementById('linq-qr-code');
            if (qrElement && typeof QRCode !== 'undefined') {
                new QRCode(qrElement, {
                    text: c.data.qr_token,
                    width: 200,
                    height: 200,
                    colorDark: '#000000',
                    colorLight: '#ffffff',
                    correctLevel: QRCode.CorrectLevel.H
                });
            }
        }, 500);
    }
};

sp_widget.css:
.sp-card {
    border: 1px solid $border-tertiary;
    border-radius: $border-radius-large;
    box-shadow: 0 1px 4px rgba($text-color, 0.07);
    background: $background-primary;
    overflow: hidden;
    margin-bottom: 24px;
    max-width: 500px;
    margin-left: auto;
    margin-right: auto;
}
.sp-card-header {
    padding: 16px 24px;
    background: $background-primary;
    border-bottom: 1px solid $border-tertiary;
}
.sp-card-title {
    font-size: $font-size-large;
    font-weight: 600;
    color: $text-color;
    margin: 0;
}
.sp-card-title .glyphicon {
    margin-right: 8px;
    color: $brand-primary;
}
.sp-card-body {
    padding: 24px;
}
.sp-pass-details h4 {
    font-size: 22px;
    font-weight: 600;
    color: $text-color;
    margin-bottom: 12px;
}
.sp-pass-details p {
    margin-bottom: 8px;
    color: $text-secondary;
    font-size: $font-size-base;
}
.sp-pass-details .glyphicon {
    margin-right: 8px;
    color: $brand-primary;
    font-size: 14px;
}
.sp-qr-container {
    padding: 24px 0;
}
#linq-qr-code {
    display: inline-block;
    padding: 16px;
    background: $background-primary;
    border: 2px solid $border-tertiary;
    border-radius: $border-radius-large;
}
.sp-qr-hint {
    margin-top: 16px;
    font-size: $font-size-small;
}

sp_widget.script:
(function() {
    data.qr_token = '';
    data.studentName = '';
    data.eventTitle = '';
    data.eventDate = '';
    data.venue = '';
    data.errorMsg = '';
    data.accessDenied = false;

    try {
        var regId = $sp.getParameter('reg_id');
        if (!regId) {
            data.errorMsg = 'No registration specified.';
            return;
        }

        var regGr = new GlideRecord('x_2097092_linq_registration');
        if (!regGr.get(regId)) {
            data.errorMsg = 'Registration not found.';
            return;
        }

        // Access control: only the student who registered can view their pass
        var studentId = regGr.getValue('student') + '';
        if (studentId !== gs.getUserID()) {
            data.accessDenied = true;
            data.errorMsg = 'You do not have access to this QR pass.';
            return;
        }

        data.qr_token = regGr.getValue('qr_token') + '';
        data.studentName = regGr.getDisplayValue('student') + '';

        // Get event details
        var eventGr = new GlideRecord('x_2097092_linq_event');
        if (eventGr.get(regGr.getValue('event'))) {
            data.eventTitle = eventGr.getValue('title') + '';
            data.eventDate = eventGr.getDisplayValue('event_date') + '';
            data.venue = eventGr.getValue('venue') + '';
        }
    } catch (e) {
        gs.error('linq-qr-pass error: ' + e.message);
        data.errorMsg = 'An error occurred loading your pass.';
    }
})();
